select a.user_id, a.user_tg_id, a.user_tg_name, a.user_tg_username, a.user_avatar, a.user_type, a.`level`, a.super_user_id, a.super_user_tg_id, a.p_path, a.shareholder_id, a.salt, a.pay_password, a.google_key, a.lan_key, a.phone, a.email, a.freeze_status, a.handle_freeze_status, a.ip, a.source, a.ip_addr, a.channel_id, a.sign_time, a.sign, a.login_time, a.create_time, a.update_time, a.update_by, a.follow_status, a.has_set_rtp, a.bot_status, utm.merchant_tag_codes AS merchant_tag_codes, COALESCE(ext_cumulative_bet.amount, 0) as cumulativeBetVolume, COALESCE(ext_bonus.amount, 0) as bonusAmount, COALESCE(ext_recharge.amount, 0) as cumulativeRecharge, (COALESCE(ext_unfinished_wager.amount, 0) - COALESCE(ext_cumulative_bet.amount, 0)) as unfinishedWagerAmount, COALESCE(wallet_usdt.amount, 0) as usdtBalanceAmount, channel.channel_name as channelName, channel.channel_code as channelCode, shareholder.name as shareholderName, ( SELECT COALESCE(SUM(op.amount), 0) FROM t_order_person op WHERE op.user_id = a.user_id AND op.currency_id = 6 AND op.order_type = 2 AND op.lower_subtype = 1 ) + ( SELECT COALESCE(SUM(ow.amount), 0) FROM t_order_withdraw ow WHERE ow.user_id = a.user_id AND ow.currency_id = 6 AND ow.order_status = 4 ) + ( SELECT COALESCE(SUM(olw.amount), 0) FROM t_order_law_withdraw olw WHERE olw.user_id = a.user_id AND olw.currency_id = 6 AND olw.order_status = 4 ) AS totalWithdrawAmount, ( SELECT COALESCE(SUM(co.customer_loss_amount), 0) FROM t_user_count_order co WHERE co.user_id = a.user_id ) AS customerLossAmount from t_user a left join t_user_ext ext_cumulative_bet on a.user_id = ext_cumulative_bet.user_id and ext_cumulative_bet.type = 2 left join t_user_ext ext_bonus on a.user_id = ext_bonus.user_id and ext_bonus.type = 6 left join t_user_ext ext_recharge on a.user_id = ext_recharge.user_id and ext_recharge.type = 7 left join t_user_ext ext_unfinished_wager on a.user_id = ext_unfinished_wager.user_id and ext_unfinished_wager.type = 3 left join t_user_wallet wallet_usdt on a.user_id = wallet_usdt.user_id and wallet_usdt.currency_id = 6 left join t_channel channel on a.channel_id = channel.id left join t_shareholder shareholder on a.shareholder_id = shareholder.id left join t_user_merchant_tag utm on a.user_id = utm.user_id where 1=1 and a.user_id = #{userId} and a.user_tg_name like concat('%', #{userTgName}, '%') and a.user_tg_username like concat('%', #{userTgUsername}, '%')
