SELECT
    a.user_id,
    a.user_tg_id,
    a.user_tg_name,
    a.user_tg_username,
    a.user_avatar,
    a.user_type,
    a.`level`,
    a.super_user_id,
    a.super_user_tg_id,
    a.p_path,
    a.shareholder_id,
    a.phone,
    a.email,
    a.freeze_status,
    a.handle_freeze_status,
    a.ip,
    a.source,
    a.ip_addr,
    a.channel_id,
    a.login_time,
    a.create_time,
    a.follow_status,
    a.has_set_rtp,
    a.bot_status,
    channel.channel_name AS channelName,
    channel.channel_code AS channelCode,
    shareholder.name AS shareholderName
FROM t_user a
         LEFT JOIN t_channel channel ON a.channel_id = channel.id
         LEFT JOIN t_shareholder shareholder ON a.shareholder_id = shareholder.id
WHERE 1=1
and a.user_id = #{userId}
and a.user_tg_name like concat('%', #{userTgName}, '%')
and a.user_tg_username like concat('%',
    #{userTgUsername}, '%')

and a.user_tg_id = #{userTgId}
and a.ip like concat('%', #{ip}, '%')
and a.email like concat('%', #{email}, '%')
and a.lan_key = #{lanKey}
and a.follow_status = #{followStatus}
and a.source = #{source}
and a.has_set_rtp = #{hasSetRtp}
and a.bot_status = #{botStatus}
and a.freeze_status = #{freezeStatus}
and a.handle_freeze_status = #{handleFreezeStatus}
and a.channel_id = #{channelId}
and a.super_user_id = #{superUserId}
and a.super_user_tg_id = #{superUserTgId}

    and (


            a.login_time between #{item,jdbcType=VARCHAR}


            and #{item,jdbcType=VARCHAR}


    )


    and (


            a.create_time between #{item,jdbcType=VARCHAR}


            and #{item,jdbcType=VARCHAR}


    )

and a.`level` = #{level}
order by a.user_id desc

SELECT user_id AS userId, COALESCE(SUM(amount), 0) AS amount FROM t_order_person WHERE user_id IN
#{id}
AND currency_id = 6 AND order_type = 2 AND lower_subtype = 1 GROUP BY user_id

SELECT user_id AS userId, COALESCE(SUM(amount), 0) AS amount FROM t_order_withdraw WHERE user_id IN
#{id}
AND currency_id = 6 AND order_status = 4 GROUP BY user_id

SELECT user_id AS userId, COALESCE(SUM(amount), 0) AS amount FROM t_order_law_withdraw WHERE user_id IN
#{id}
AND currency_id = 6 AND order_status = 4 GROUP BY user_id

SELECT user_id AS userId, COALESCE(SUM(customer_loss_amount), 0) AS amount FROM t_user_count_order WHERE user_id IN
#{id}
GROUP BY user_id

SELECT user_id AS userId, COALESCE(SUM(CASE WHEN type = 3 THEN COALESCE(amount, 0) ELSE 0 END), 0) AS withdrawWager, COALESCE(SUM(CASE WHEN type = 2 THEN COALESCE(amount, 0) ELSE 0 END), 0) AS cumWager FROM t_user_ext WHERE user_id IN
#{id}
AND type IN (2, 3) GROUP BY user_id
